/* ═══════════════════════════════════════════════════════
   HELPERS — Age Group Detection
   ═══════════════════════════════════════════════════════ */

function resolveAgeGroup(profile) {
  const raw = profile?.ageGroup || profile?.age_group || '';
  if (raw) {
    const lc = raw.toLowerCase();
    if (lc.includes('0') && (lc.includes('6 m') || lc.includes('0-6') || lc.includes('0–6'))) return '0-6m';
    if ((lc.includes('6') && lc.includes('12')) || lc.includes('6-12') || lc.includes('6–12')) return '6-12m';
    if (lc.includes('1') && (lc.includes('1.5') || lc.includes('18')) && !lc.includes('2')) return '12-18m';
    if (lc.includes('1.5') || lc.includes('18') || (lc.includes('1') && lc.includes('2') && !lc.includes('2.5'))) return '18-24m';
    if (lc.includes('2') && (lc.includes('2.5') || lc.includes('30'))) return '24-30m';
    if (lc.includes('2.5') || lc.includes('30')) return '30-36m';
  }
  const age = parseFloat(profile?.age || 0);
  if (age >= 0   && age < 0.5)  return '0-6m';
  if (age >= 0.5 && age < 1)    return '6-12m';
  if (age >= 1   && age < 1.5)  return '12-18m';
  if (age >= 1.5 && age < 2)    return '18-24m';
  if (age >= 2   && age < 2.5)  return '24-30m';
  if (age >= 2.5 && age <= 3)   return '30-36m';
  return null;
}

