/* ═══════════════════════════════════════════════════════
   DIFFICULTY COLORS
   ═══════════════════════════════════════════════════════ */

const DIFF_COLORS = {
  Beginner:     { bg: '#E8F5E9', text: '#2E7D32', border: '#A5D6A7' },
  Intermediate: { bg: '#FFF8E1', text: '#F57C00', border: '#FFE082' },
  Advanced:     { bg: '#EDE7F6', text: '#6A1B9A', border: '#CE93D8' },
};

/* ═══════════════════════════════════════════════════════
   NOTES MODAL
   ═══════════════════════════════════════════════════════ */

function NotesModal({ activity, note, onSave, onClose }) {
  const [text, setText] = useState(note || '');
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className={s.modalOverlay}
      onClick={onClose}
    >
      <motion.div
        initial={{ scale: 0.92, y: 20 }}
        animate={{ scale: 1, y: 0 }}
        exit={{ scale: 0.92, y: 20 }}
        className={s.modalCard}
        onClick={e => e.stopPropagation()}
      >
        <div className={s.modalHeader}>
          <span className={s.modalEmoji}>{activity.emoji}</span>
          <div>
            <h3 className={s.modalTitle}>Notes — {activity.title}</h3>
            <p className={s.modalSub}>Observations, adaptations, or next steps</p>
          </div>
        </div>
        <textarea
          className={s.noteTextarea}
          value={text}
          onChange={e => setText(e.target.value)}
          placeholder="Type your observations here…"
          rows={5}
          autoFocus
        />
        <div className={s.modalActions}>
          <button className={s.btnGhost} onClick={onClose}>Cancel</button>
          <button className={s.btnPrimary} onClick={() => { onSave(text); onClose(); }}>
            💾 Save Note
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
}

/* ═══════════════════════════════════════════════════════
   ACTIVITY CARD
   ═══════════════════════════════════════════════════════ */

function ActivityCard({ activity, isCompleted, note, onToggleComplete, onOpenNote }) {
  const [expanded, setExpanded] = useState(false);
  const diff = DIFF_COLORS[activity.difficulty] || DIFF_COLORS.Beginner;

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -10 }}
      whileHover={{ y: -4, boxShadow: '0 12px 32px rgba(124,77,255,0.12)' }}
      className={`${s.card} ${isCompleted ? s.cardComplete : ''}`}
    >
      {/* Card Header */}
      <div className={s.cardHeader}>
        <div className={s.cardIconWrap}>
          <span className={s.cardEmoji}>{activity.emoji}</span>
        </div>
        <div className={s.cardMeta}>
          <h3 className={s.cardTitle}>{activity.title}</h3>
          <div className={s.cardBadges}>
            <span className={s.badgeAge}>{AGE_GROUP_LABELS[activity.ageGroup]}</span>
            <span
              className={s.badgeDiff}
              style={{ background: diff.bg, color: diff.text, border: `1.5px solid ${diff.border}` }}
            >
              {activity.difficulty}
            </span>
            <span className={s.badgeDuration}>⏱ {activity.duration}</span>
          </div>
        </div>
        {isCompleted && (
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className={s.completedBadge}
          >
            ✅
          </motion.div>
        )}
      </div>

      {/* Description */}
      <p className={s.cardDescription}>{activity.description}</p>

      {/* Skill Tags */}
      <div className={s.skillTags}>
        {activity.skills.map(skill => (
          <span key={skill} className={s.skillTag}>{skill}</span>
        ))}
      </div>

      {/* Expandable Details */}
      <button
        className={s.expandBtn}
        onClick={() => setExpanded(e => !e)}
        aria-expanded={expanded}
      >
        {expanded ? '▲ Hide Details' : '▼ Show Details & Game Ideas'}
      </button>
      <AnimatePresence>
        {expanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className={s.expandContent}
          >
            {activity.objective && (
              <div className={s.detailRow}>
                <span className={s.detailLabel}>🎯 Objective</span>
                <p className={s.detailText}>{activity.objective}</p>
              </div>
            )}
            {activity.gameIdea && (
              <div className={s.detailRow}>
                <span className={s.detailLabel}>🎮 Game Idea</span>
                <p className={s.detailText}>{activity.gameIdea}</p>
              </div>
            )}
            {activity.aiIntegration && (
              <div className={s.detailRow}>
                <span className={s.detailLabel}>🤖 AI Integration</span>
                <p className={s.detailText}>{activity.aiIntegration}</p>
              </div>
            )}
            {activity.learningOutcome && (
              <div className={s.detailRow}>
                <span className={s.detailLabel}>✨ Learning Outcome</span>
                <p className={s.detailText}>{activity.learningOutcome}</p>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Note indicator */}
      {note && (
        <div className={s.notePreview}>
          📝 <em>{note.slice(0, 60)}{note.length > 60 ? '…' : ''}</em>
        </div>
      )}

      {/* Actions */}
      <div className={s.cardActions}>
        <motion.button
          whileHover={{ scale: 1.04 }}
          whileTap={{ scale: 0.95 }}
          className={isCompleted ? s.btnComplete : s.btnPrimary}
          onClick={() => onToggleComplete(activity.id)}
        >
          {isCompleted ? '✅ Completed' : '○ Mark Complete'}
        </motion.button>
        <motion.button
          whileHover={{ scale: 1.04 }}
          whileTap={{ scale: 0.95 }}
          className={s.btnGhost}
          onClick={() => onOpenNote(activity)}
        >
          📝 {note ? 'Edit Note' : 'Add Note'}
        </motion.button>
      </div>
    </motion.div>
  );
}

/* ═══════════════════════════════════════════════════════
   BADGE CARD
   ═══════════════════════════════════════════════════════ */

function BadgeCard({ badge, unlocked }) {
  return (
    <motion.div
      whileHover={unlocked ? { y: -4, scale: 1.04 } : {}}
      className={`${s.badgeCard} ${unlocked ? s.badgeUnlocked : s.badgeLocked}`}
    >
      <div className={s.badgeEmoji} style={{ filter: unlocked ? 'none' : 'grayscale(1)' }}>
        {badge.emoji}
      </div>
      <h4 className={s.badgeName}>{badge.title}</h4>
      <p className={s.badgeDesc}>{badge.description}</p>
      {unlocked && (
        <motion.span
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          className={s.badgeUnlockedLabel}
        >
          🏅 Unlocked!
        </motion.span>
      )}
    </motion.div>
  );
}

/* ═══════════════════════════════════════════════════════
   MAIN PAGE
   ═══════════════════════════════════════════════════════ */

export default function SpatialBrainPage() {
  const { profile } = useUser();
  const { activeChild } = useChildProfile();

  const childProfile = activeChild || profile;
  const ageGroup = useMemo(() => resolveAgeGroup(childProfile), [childProfile]);

  const [activeFilter, setActiveFilter] = useState('all');
  const [completed, setCompleted] = useState(() => {
    try {
      const stored = localStorage.getItem('spaceece_spatial_completed');
      return new Set(stored ? JSON.parse(stored) : []);
    } catch { return new Set(); }
  });
  const [notes, setNotes] = useState(() => {
    try {
      return JSON.parse(localStorage.getItem('spaceece_spatial_notes') || '{}');
    } catch { return {}; }
  });
  const [noteModal, setNoteModal] = useState(null);
  const [showConfetti, setShowConfetti] = useState(false);
  const prevCompletedCount = useRef(completed.size);

  useEffect(() => {
    localStorage.setItem('spaceece_spatial_completed', JSON.stringify([...completed]));
    const ageActivities = ACTIVITIES.filter(a => a.ageGroup === ageGroup);
    const score = ageActivities.length > 0
      ? Math.round((ageActivities.filter(a => completed.has(a.id)).length / ageActivities.length) * 100)
      : 0;
    const analyticsData = JSON.parse(localStorage.getItem('spaceece_domain_scores') || '{}');
    analyticsData['Spatial'] = score;
    localStorage.setItem('spaceece_domain_scores', JSON.stringify(analyticsData));
  }, [completed, ageGroup]);

  useEffect(() => {
    localStorage.setItem('spaceece_spatial_notes', JSON.stringify(notes));
  }, [notes]);

  useEffect(() => {
    if (completed.size > prevCompletedCount.current) {
      setShowConfetti(true);
      setTimeout(() => setShowConfetti(false), 2500);
    }
    prevCompletedCount.current = completed.size;
  }, [completed]);

  const ageActivities = useMemo(
    () => ACTIVITIES.filter(a => a.ageGroup === ageGroup),
    [ageGroup]
  );

  const filteredActivities = useMemo(() => {
    if (activeFilter === 'all') return ageActivities;
    return ageActivities.filter(a => a.skills.includes(activeFilter));
  }, [ageActivities, activeFilter]);

  const completedCount = ageActivities.filter(a => completed.has(a.id)).length;
  const progressPct = ageActivities.length > 0
    ? Math.round((completedCount / ageActivities.length) * 100)
    : 0;

  const badgeStates = useMemo(
    () => BADGES.map(b => ({ ...b, unlocked: b.condition(completed, ACTIVITIES) })),
    [completed]
  );

  const toggleComplete = (id) => {
    setCompleted(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const saveNote = (activityId, text) => {
    setNotes(prev => ({ ...prev, [activityId]: text }));
  };

  if (!ageGroup) {
    return (
      <div style={{ minHeight: '60vh', display: 'flex', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 16 }}>
        <span style={{ fontSize: '4rem' }}>🔒</span>
        <h2 style={{ fontFamily: 'var(--font-display)', color: 'var(--color-text)' }}>
          This section is for children aged 0–3 years.
        </h2>
        <p style={{ color: 'var(--color-text-secondary)' }}>
          Please select a child profile with an age in the 0–3 years curriculum.
        </p>
      </div>
    );
  }

  return (
    <div className={s.page}>
      <ConfettiEffect active={showConfetti} />
      <FloatingElements count={3} />

      {/* ── Hero Banner ── */}
      <motion.div
        initial={{ opacity: 0, y: -18 }}
        animate={{ opacity: 1, y: 0 }}
        className={s.hero}
      >
        <div className={s.heroDecor}>🌟</div>
        <div className={s.heroContent}>
          <div className={s.heroBadge}>Annual Curriculum (Levels 1–6)</div>
          <h1 className={s.heroTitle}>E-Activity &amp; Educational Game Catalog</h1>
          <p className={s.heroSub}>
            Developmental milestones &amp; activities for <strong>{AGE_GROUP_LABELS[ageGroup]}</strong>
          </p>
          <div className={s.heroProgress}>
            <div className={s.heroProgressBar}>
              <motion.div
                className={s.heroProgressFill}
                initial={{ width: 0 }}
                animate={{ width: `${progressPct}%` }}
                transition={{ duration: 1, ease: 'easeOut' }}
              />
            </div>
            <span className={s.heroProgressText}>
              {completedCount} / {ageActivities.length} completed · {progressPct}%
            </span>
          </div>
        </div>
        <div className={s.ageChips}>
          {Object.entries(AGE_GROUP_LABELS).map(([key, label]) => (
            <span
              key={key}
              className={`${s.ageChip} ${key === ageGroup ? s.ageChipActive : ''}`}
            >
              {label}
            </span>
          ))}
        </div>
      </motion.div>

      {/* ── Layout: Sidebar + Main ── */}
      <div className={s.layout}>

        {/* Right Sidebar Filters */}
        <aside className={s.sidebar}>
          <h2 className={s.sidebarTitle}>🔍 Filter by Domain</h2>
          <nav className={s.sidebarNav}>
            {SKILL_FILTERS.map(f => (
              <button
                key={f.id}
                className={`${s.filterBtn} ${activeFilter === f.id ? s.filterBtnActive : ''}`}
                onClick={() => setActiveFilter(f.id)}
              >
                <span className={s.filterEmoji}>{f.emoji}</span>
                <span className={s.filterLabel}>{f.label}</span>
              </button>
            ))}
          </nav>

          <div className={s.sidebarStats}>
            <div className={s.sidebarStat}>
              <span className={s.sidebarStatValue}>{completedCount}</span>
              <span className={s.sidebarStatLabel}>Completed</span>
            </div>
            <div className={s.sidebarStat}>
              <span className={s.sidebarStatValue}>{ageActivities.length - completedCount}</span>
              <span className={s.sidebarStatLabel}>Remaining</span>
            </div>
            <div className={s.sidebarStat}>
              <span className={s.sidebarStatValue}>{badgeStates.filter(b => b.unlocked).length}</span>
              <span className={s.sidebarStatLabel}>Badges</span>
            </div>
          </div>
        </aside>

        {/* Main Content */}
        <main className={s.main}>

          <div className={s.mainHeader}>
            <h2 className={s.mainHeading}>
              {SKILL_FILTERS.find(f => f.id === activeFilter)?.emoji}{' '}
              {activeFilter === 'all' ? 'All Domains' : activeFilter}
              <span className={s.mainCount}>{filteredActivities.length} activities</span>
            </h2>
          </div>

          {filteredActivities.length === 0 ? (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              className={s.empty}
            >
              <span className={s.emptyIcon}>🔍</span>
              <p>No activities match this filter for {AGE_GROUP_LABELS[ageGroup]}.</p>
              <button className={s.btnGhost} onClick={() => setActiveFilter('all')}>
                Show All Domains
              </button>
            </motion.div>
          ) : (
            <motion.div
              layout
              className={s.cardsGrid}
            >
              <AnimatePresence mode="popLayout">
                {filteredActivities.map(act => (
                  <ActivityCard
                    key={act.id}
                    activity={act}
                    isCompleted={completed.has(act.id)}
                    note={notes[act.id] || ''}
                    onToggleComplete={toggleComplete}
                    onOpenNote={(a) => setNoteModal(a)}
                  />
                ))}
              </AnimatePresence>
            </motion.div>
          )}

          {/* ── Badges Section ── */}
          <motion.section
            initial={{ opacity: 0, y: 24 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className={s.badgesSection}
          >
            <h2 className={s.badgesSectionTitle}>🏅 Domain Badges</h2>
            <p className={s.badgesSectionSub}>
              Complete activities across all age groups to unlock these rewards!
            </p>
            <div className={s.badgesGrid}>
              {badgeStates.map(badge => (
                <BadgeCard key={badge.id} badge={badge} unlocked={badge.unlocked} />
              ))}
            </div>
          </motion.section>

        </main>
      </div>

      {/* Notes Modal */}
      <AnimatePresence>
        {noteModal && (
          <NotesModal
            activity={noteModal}
            note={notes[noteModal.id] || ''}
            onSave={(text) => saveNote(noteModal.id, text)}
            onClose={() => setNoteModal(null)}
          />
        )}
      </AnimatePresence>
    </div>
  );
}
